import axios from "axios";

// Use environment variable or fallback
const API_URL = process.env.REACT_APP_API_URL || "http://localhost:8080/api";

const api = axios.create({
  baseURL: API_URL,
  headers: {
    "Content-Type": "application/json",
  },
});

// Attach auth functions directly to api object
api.signup = async (email, password) => {
  return api.post("/auth/signup", { email, password });
};

api.login = async (email, password) => {
  return api.post("/auth/login", { email, password });
};

api.getVehicles = async () => {
  const token = localStorage.getItem("token");
  return api.get("/vehicles", {
    headers: { Authorization: `Bearer ${token}` },
  });
};

api.addVehicle = async (vehicle) => {
  const token = localStorage.getItem("token");
  return api.post("/vehicles", vehicle, {
    headers: { Authorization: `Bearer ${token}` },
  });
};

api.optimizeRoute = async (routeRequest) => {
  const token = localStorage.getItem("token");
  return api.post("/routes/optimize", routeRequest, {
    headers: { Authorization: `Bearer ${token}` },
  });
};

api.getAlerts = async () => {
  const token = localStorage.getItem("token");
  return api.get("/alerts", {
    headers: { Authorization: `Bearer ${token}` },
  });
};

export default api;
